<script>
import appFooter from '../components/Footer';
import { gets, posts } from '../util/api';
export default {
  components: { appFooter },
  data() {
    return {
      // HomeArr1: [],
      // HomeArr2: [],
      // HomeArr4: [],
      // HomeArr5: [],
      list: [],
      show: false,
      zqd_banner: [], //轮播图
      zqd_list: [], //列表数据
    };
  },
  created() {},
  mounted() {
    this.getList();
    this.banner();
  },
  methods: {
    // 获取首页列表
    async getList() {
      let { data } = await gets('/api/app/recommend/appIndex');
      // console.log(data)
      this.zqd_list = data.data;
      // console.log(this.zqd_list);
    },
    async banner() {
      //  请求轮播图
      let { data } = await gets('/api/app/banner');
      // console.log(data)
      this.zqd_banner = data.data;
    },
    // 讲师详情
    zqd_denglupanduan(id) {
      let zqd_token = localStorage.getItem('token');
      if (zqd_token) {
        this.$router.push({
          path: '/teacher',
          query: {
            id,
          },
        });
      } else {
        this.show = true;
      }
    },
    // 课程详情
    jingpin(id) {
      this.$router.push({
        path: '/course-detail',
        query: {
          id,
        },
      });
    },
  },
};
</script>

